def solve(*args):
    # Implementing core Projects endpoints
    from fastapi import FastAPI, HTTPException
    from pydantic import BaseModel
    from typing import List, Optional

    app = FastAPI()

    class Project(BaseModel):
        id: int
        name: str
        description: Optional[str] = None

    projects_db = []

    @app.post("/projects/", response_model=Project)
    def create_project(project: Project):
        projects_db.append(project)
        return project

    @app.get("/projects/", response_model=List[Project])
    def get_projects(fields: Optional[str] = None):
        if fields:
            field_list = fields.split(',')
            return [{field: getattr(project, field) for field in field_list if hasattr(project, field)} for project in projects_db]
        return projects_db

    @app.get("/projects/{project_id}", response_model=Project)
    def get_project(project_id: int):
        for project in projects_db:
            if project.id == project_id:
                return project
        raise HTTPException(status_code=404, detail="Project not found")

    @app.put("/projects/{project_id}", response_model=Project)
    def update_project(project_id: int, project: Project):
        for index, existing_project in enumerate(projects_db):
            if existing_project.id == project_id:
                projects_db[index] = project
                return project
        raise HTTPException(status_code=404, detail="Project not found")

    @app.delete("/projects/{project_id}")
    def delete_project(project_id: int):
        for index, existing_project in enumerate(projects_db):
            if existing_project.id == project_id:
                del projects_db[index]
                return {"detail": "Project deleted"}
        raise HTTPException(status_code=404, detail="Project not found")

    return app
